import java.io.IOException;
import java.io.ObjectInputStream;

/**
 * Serialization service for object persistence and network transmission.
 * Provides functionality to deserialize objects from byte arrays.
 */
public class SerializationService {

    /**
     * Deserializes an object from the provided byte array.
     *
     * @param serializedData the byte array containing serialized object data
     * @return the deserialized object
     * @throws IOException if an I/O error occurs during deserialization
     * @throws ClassNotFoundException if the class of the serialized object cannot be found
     * @throws IllegalArgumentException if the input data is null or empty
     */
    public Object deserializeObject(byte[] serializedData) throws IOException, ClassNotFoundException {
        // Validate input parameter
        if (serializedData == null) {
            throw new IllegalArgumentException("Serialized data cannot be null");
        }

        if (serializedData.length == 0) {
            throw new IllegalArgumentException("Serialized data cannot be empty");
        }

        // Use try-with-resources for automatic resource cleanup
        try (ByteArrayInputStream byteArrayStream = new ByteArrayInputStream(serializedData);
             ObjectInputStream objectStream = new ObjectInputStream(byteArrayStream)) {

            // Perform deserialization
            return objectStream.readObject();

        } catch (IOException | ClassNotFoundException e) {
            // Re-throw the original exceptions as per method signature
            throw e;
        }
    }
}

